function goal(
  id: string,
  label: string,
  intent: CaseGoal["intent"],
  priority: CaseGoal["priority"],
  rationale: string,
  matcher: CaseGoal["matcher"],
  learningTopicIds: string[]
): CaseGoal {
  return { id, label, intent, priority, rationale, matcher, learningTopicIds };
}

